public class FileUploadDto
{
    public string FilePath { get; set; }
    public string FileName { get; set; }
    public long FileSize { get; set; }
    public string FileType { get; set; }
    public string Message { get; set; }
}

[ApiController]
[Route("api/[controller]")]
public class UploadController : ControllerBase
{
    private readonly IWebHostEnvironment _environment;
    private readonly long _maxFileSize = 10 * 1024 * 1024;

    private readonly Dictionary<string, List<string>> _allowedFileTypes = new()
    {
        { "avatar", new List<string> { ".jpg", ".jpeg", ".png", ".gif", ".bmp", ".webp" } },
        { "document", new List<string> 
            { 
                ".pdf", 
                ".doc", ".docx", 
                ".xls", ".xlsx", 
                ".ppt", ".pptx",
                ".txt",
                ".csv"
            } 
        }
    };

    public UploadController(IWebHostEnvironment environment)
    {
        _environment = environment;
    }

    [HttpPost("avatar")]
    [RequestSizeLimit(10485760)]
    public async Task<ActionResult<FileUploadDto>> UploadAvatar(IFormFile file)
    {
        return await UploadFile(file, "avatar");
    }

    [HttpPost("document")]
    [RequestSizeLimit(10485760)]
    public async Task<ActionResult<FileUploadDto>> UploadDocument(IFormFile file)
    {
        return await UploadFile(file, "document");
    }

    [HttpPost]
    [RequestSizeLimit(10485760)]
    public async Task<ActionResult<FileUploadDto>> Upload(IFormFile file, [FromQuery] string type = "document")
    {
        return await UploadFile(file, type);
    }

    private async Task<ActionResult<FileUploadDto>> UploadFile(IFormFile file, string type)
    {
        if (file == null || file.Length == 0)
        {
            return BadRequest(new FileUploadDto 
            { 
                Message = "No file uploaded or file is empty" 
            });
        }

        if (file.Length > _maxFileSize)
        {
            return BadRequest(new FileUploadDto 
            { 
                Message = $"File size exceeds maximum allowed size of {_maxFileSize / 1024 / 1024}MB" 
            });
        }

        var fileExtension = Path.GetExtension(file.FileName).ToLowerInvariant();

        if (!_allowedFileTypes.ContainsKey(type))
        {
            return BadRequest(new FileUploadDto 
            { 
                Message = $"Invalid upload type. Allowed types: {string.Join(", ", _allowedFileTypes.Keys)}" 
            });
        }

        if (!_allowedFileTypes[type].Contains(fileExtension))
        {
            return BadRequest(new FileUploadDto 
            { 
                Message = $"File type not allowed. Allowed extensions for {type}: {string.Join(", ", _allowedFileTypes[type])}" 
            });
        }

        var uploadsFolder = Path.Combine(_environment.WebRootPath, "uploads", type);
        
        if (!Directory.Exists(uploadsFolder))
        {
            Directory.CreateDirectory(uploadsFolder);
        }

        var uniqueFileName = $"{Guid.NewGuid()}_{Path.GetFileName(file.FileName)}";
        var filePath = Path.Combine(uploadsFolder, uniqueFileName);

        try
        {
            using (var stream = new FileStream(filePath, FileMode.Create))
            {
                await file.CopyToAsync(stream);
            }

            var relativePath = $"/uploads/{type}/{uniqueFileName}";

            return Ok(new FileUploadDto
            {
                FilePath = relativePath,
                FileName = file.FileName,
                FileSize = file.Length,
                FileType = fileExtension,
                Message = "File uploaded successfully"
            });
        }
        catch (Exception ex)
        {
            return StatusCode(500, new FileUploadDto 
            { 
                Message = $"Error uploading file: {ex.Message}" 
            });
        }
    }

    [HttpDelete]
    public IActionResult DeleteFile([FromQuery] string filePath)
    {
        if (string.IsNullOrWhiteSpace(filePath))
        {
            return BadRequest(new { Message = "File path is required" });
        }

        if (!filePath.StartsWith("/uploads/"))
        {
            return BadRequest(new { Message = "Invalid file path" });
        }

        var physicalPath = Path.Combine(_environment.WebRootPath, filePath.TrimStart('/').Replace('/', Path.DirectorySeparatorChar));

        if (!System.IO.File.Exists(physicalPath))
        {
            return NotFound(new { Message = "File not found" });
        }

        try
        {
            System.IO.File.Delete(physicalPath);
            return Ok(new { Message = "File deleted successfully" });
        }
        catch (Exception ex)
        {
            return StatusCode(500, new { Message = $"Error deleting file: {ex.Message}" });
        }
    }

    [HttpGet("info")]
    public IActionResult GetUploadInfo()
    {
        return Ok(new
        {
            MaxFileSize = _maxFileSize,
            MaxFileSizeMB = _maxFileSize / 1024 / 1024,
            AllowedFileTypes = _allowedFileTypes
        });
    }
}

